-- Comprehensive demo responses for all 20 complaint examples
-- Ensures idempotent upsert so this migration can be run safely multiple times

ON CONFLICT (complaint_reference) DO UPDATE SET
  key_findings = EXCLUDED.key_findings,
  actions_taken = EXCLUDED.actions_taken,
  improvements_made = EXCLUDED.improvements_made,
  additional_context = EXCLUDED.additional_context;

